from collections import deque


class _N:
    __slots__ = ("val", "left", "right")
    def __init__(self, v): self.val = v; self.left = None; self.right = None


def _serialize(root):
    if not root: return []
    out = []; q = deque([root])
    while q:
        n = q.popleft()
        if n is None: out.append(None); continue
        out.append(n.val); q.append(n.left); q.append(n.right)
    while out and out[-1] is None: out.pop()
    return out


def construct_tree(preorder, inorder):
    index_of = {v: i for i, v in enumerate(inorder)}
    pre_pos = [0]

    def build(lo, hi):
        if lo > hi:
            return None
        root_val = preorder[pre_pos[0]]
        pre_pos[0] += 1
        root = _N(root_val)
        mid = index_of[root_val]
        root.left = build(lo, mid - 1)
        root.right = build(mid + 1, hi)
        return root

    root = build(0, len(inorder) - 1)
    return _serialize(root)
